import numpy as np

class KNNImputer:
    def __init__(self, k: int = 5):
        self.k = k

    def fit(self, X: np.ndarray) -> 'KNNImputer':
        self.X_train_ = X.copy().astype(float)
        self.col_means_ = np.nanmean(X, axis=0)
        return self

    def transform(self, X: np.ndarray) -> np.ndarray:
        X_out = X.copy().astype(float)
        n_rows, n_cols = X_out.shape

        for i in range(n_rows):
            missing_cols = np.where(np.isnan(X_out[i]))[0]
            if len(missing_cols) == 0:
                continue

            obs_i = np.where(~np.isnan(X_out[i]))[0]

            for j in missing_cols:
                # Find train rows with observed value in column j
                candidate_mask = ~np.isnan(self.X_train_[:, j])
                candidates = np.where(candidate_mask)[0]

                if len(candidates) == 0:
                    X_out[i, j] = self.col_means_[j]
                    continue

                # Compute distances using shared observed features
                dists = []
                for c_idx in candidates:
                    shared = obs_i[~np.isnan(self.X_train_[c_idx, obs_i])]
                    if len(shared) == 0:
                        dists.append(np.inf)
                    else:
                        diff = X_out[i, shared] - self.X_train_[c_idx, shared]
                        dists.append(np.sqrt(np.dot(diff, diff)))

                dists = np.array(dists)
                k_eff = min(self.k, len(candidates))
                nn_idx = candidates[np.argsort(dists)[:k_eff]]
                X_out[i, j] = np.mean(self.X_train_[nn_idx, j])

        return X_out

    def fit_transform(self, X: np.ndarray) -> np.ndarray:
        return self.fit(X).transform(X)
